const rows = $input.all().map(i => i.json);

return [{ json: {
  generated_at: new Date().toISOString(),
  counts: rows.map(r => ({
    source:      r.source,
    subcategory: r.subcategory,
    obj_type:    r.obj_type,
    name:        r.name,
    row_count:   r.row_count
  }))
} }];
